import mahasiswaApi from '../../api/controller/mahasiswa'
const state = {
  students: []
}

const mutations = {
  SET_MAHASISWA: (state, payload) => {
    state.students = payload
  }
}

const actions = {
  getMahasiswa: (state) => {
    mahasiswaApi.getStudents((response) => {
      state.commit('SET_MAHASISWA', response.data.content)
      console.log('success')
      console.log(response)
    }, (error, response) => {
      console.log('error')
      console.log(error)
    })
  }
}

const getters = {
  students: (state) => {
    return state.students
  }
}

const namespaced = true

export default { state, mutations, actions, getters, namespaced }
